CREATE TABLE utilities_edges (
	edges_id text not null,
	from_node numeric(24, 8) NULL,
	to_node numeric(24, 8) NULL,
	alert bool NULL
);

CREATE TABLE utilities_edges_sample_pos (
	id text NULL,
	point_2d geometry NULL,
	point_3d geometry NULL,
	line geometry NULL,
	rectangle geometry NULL,
	polygon geometry NULL,
	floor text NULL,
	hopara_scope text NULL,
    hopara_size integer NULL,
    hopara_size_reference_zoom numeric(24,8) NULL,
    hopara_color text NULL,
    hopara_scale integer NULL
);

CREATE INDEX utilities_edges_sample_pos_id ON utilities_edges_sample_pos USING btree (id);
CREATE INDEX utilities_edges_sample_pos_line_spatial ON utilities_edges_sample_pos USING gist (line);
CREATE INDEX utilities_edges_sample_pos_point_2d_spatial ON utilities_edges_sample_pos USING gist (point_2d);
CREATE INDEX utilities_edges_sample_pos_point_3d_spatial ON utilities_edges_sample_pos USING gist (point_3d);
CREATE INDEX utilities_edges_sample_pos_polygon_spatial ON utilities_edges_sample_pos USING gist (polygon);
CREATE INDEX utilities_edges_sample_pos_rectangle_spatial ON utilities_edges_sample_pos USING gist (rectangle);
CREATE INDEX utilities_edges_sample_pos_hopara_scope ON utilities_edges_sample_pos USING btree (hopara_scope);


CREATE TABLE utilities_metrics (
	sensor_id text NULL,
	"timestamp" timestamp NULL,
	measurement int4 NULL
);

CREATE TABLE utilities_neighborhoods (
	"name" text NULL
);

CREATE TABLE utilities_neighborhoods_sample_pos (
	id text NULL,
	point_2d geometry NULL,
	point_3d geometry NULL,
	line geometry NULL,
	rectangle geometry NULL,
	polygon geometry NULL,
	floor text NULL,
	hopara_scope text NULL,
	hopara_size integer NULL,
    hopara_size_reference_zoom numeric(24,8) NULL,
    hopara_color text NULL,
    hopara_scale integer NULL
);

CREATE INDEX utilities_neighborhoods_sample_pos_id ON utilities_neighborhoods_sample_pos USING btree (id);
CREATE INDEX utilities_neighborhoods_sample_pos_line_spatial ON utilities_neighborhoods_sample_pos USING gist (line);
CREATE INDEX utilities_neighborhoods_sample_pos_point_2d_spatial ON utilities_neighborhoods_sample_pos USING gist (point_2d);
CREATE INDEX utilities_neighborhoods_sample_pos_point_3d_spatial ON utilities_neighborhoods_sample_pos USING gist (point_3d);
CREATE INDEX utilities_neighborhoods_sample_pos_polygon_spatial ON utilities_neighborhoods_sample_pos USING gist (polygon);
CREATE INDEX utilities_neighborhoods_sample_pos_rectangle_spatial ON utilities_neighborhoods_sample_pos USING gist (rectangle);
CREATE INDEX utilities_neighborhoods_sample_pos_hopara_scope ON utilities_neighborhoods_sample_pos USING btree (hopara_scope);


CREATE TABLE utilities_nodes (
	node_id int NULL,
	neighborhoods text null,
	"type" text NULL,
	"name" text NULL
);

CREATE TABLE utilities_nodes_sample_pos (
	id text NULL,
	point_2d geometry NULL,
	point_3d geometry NULL,
	line geometry NULL,
	rectangle geometry NULL,
	polygon geometry NULL,
	floor text NULL,
	hopara_scope text NULL,
	hopara_size integer NULL,
    hopara_size_reference_zoom numeric(24,8) NULL,
    hopara_color text NULL,
    hopara_scale integer NULL
);

CREATE INDEX utilities_nodes_sample_pos_id ON utilities_nodes_sample_pos USING btree (id);
CREATE INDEX utilities_nodes_sample_pos_line_spatial ON utilities_nodes_sample_pos USING gist (line);
CREATE INDEX utilities_nodes_sample_pos_point_2d_spatial ON utilities_nodes_sample_pos USING gist (point_2d);
CREATE INDEX utilities_nodes_sample_pos_point_3d_spatial ON utilities_nodes_sample_pos USING gist (point_3d);
CREATE INDEX utilities_nodes_sample_pos_polygon_spatial ON utilities_nodes_sample_pos USING gist (polygon);
